{
  "title": "Aurora फ़ेलओवर तंत्र",
  "group": "Aurora उच्च उपलब्धता",
  "options": [
    {
      "text": "मैन्युअल हस्तक्षेप आवश्यक है"
    },
    {
      "text": "एप्लिकेशन पुनः कॉन्फ़िगरेशन की आवश्यकता होती है"
    },
    {
      "text": "हमेशा सबसे पुराने रेप्लिका पर फ़ेलओवर होता है"
    },
    {
      "text": "फ़ेलओवर प्राथमिकता टियर के आधार पर स्वचालित प्रमोशन"
    }
  ],
  "questionProse": [
    "कई रीड रेप्लिका वाले Aurora क्लस्टर में, जब प्राइमरी इंस्टेंस फ़ेल हो जाता है तो ऑटोमैटिक फ़ेलओवर के दौरान क्या होता है?"
  ],
  "explanationProse": [
    "Aurora फ़ेलओवर प्रक्रिया:\n      1. प्राइमरी इंस्टेंस के फ़ेल होने का पता लगाता है\n      2. फ़ेलओवर प्राथमिकता टियर के आधार पर एक Aurora रेप्लिका चुनता है\n      3. यदि प्राथमिकताएँ समान हों, तो इंस्टेंस की विशेषताओं को टाई-ब्रेकर के रूप में इस्तेमाल करता है\n      4. क्लस्टर एंडपॉइंट को स्वचालित रूप से अपडेट कर देता है\n\n      बेस्ट प्रैक्टिसेज़:\n      - विभिन्न AZs में कई रेप्लिका रखें\n      - प्रमोशन टियर्स को समझदारी से कॉन्फ़िगर करें\n      - एप्लिकेशन में हमेशा क्लस्टर एंडपॉइंट का ही उपयोग करें\n      - फ़ेलओवर सीनारियो का नियमित परीक्षण करें"
  ]
}
